INSERT INTO `philosophies` (`id`, `icon`, `title`, `message`, `created_at`, `updated_at`) VALUES
(1, '🍽️', 'Excelencia', 'La calidad no es un detalle, es el punto de partida en cada elaboración.', '2026-03-01 09:45:29', '2026-03-05 11:10:18'),
(2, '🌿', 'Origen', 'Respetamos el producto y honramos a quienes lo cultivan y lo producen.', '2026-03-01 09:45:29', '2026-03-12 16:06:00'),
(3, '🔥', 'Carácter', 'Sabores definidos, identidad propia y equilibrio en cada plato.', '2026-03-01 09:45:29', '2026-03-01 09:45:29'),
(4, '🤍', 'Cercanía', 'Un trato humano y cercano que convierte cada visita en algo personal.', '2026-03-01 09:45:29', '2026-03-01 09:45:29'),
(5, '♻️', 'Responsabilidad', 'Comprometidos con el entorno y con una cocina sostenible.', '2026-03-01 09:45:29', '2026-03-01 11:24:24'),
(6, '✨', 'Creatividad', 'Tradición y técnica contemporánea en constante evolución.', '2026-03-01 09:45:29', '2026-03-01 09:45:29');

